import {
	assign,
	call,
	getValue,
	isArray,
	isFunction,
	isPromise,
	noop,
	nothing,
	queueMicrotask,
	removeFromArray,
	Symbol,
	walkParents,
} from './std.js'

/**
 * This is so far the core of Solid JS 1.x Reactivity, but ported to
 * classes and adapted to my taste.
 *
 * Adaptation for potas needs include:
 *
 * - Ported to Classes what does fit
 * - Signal has any options
 * - Writing to a signal returns `boolean` to tell if the value changed
 * - Signal is an object that could be used as signal.read/write or
 *   destructuring
 * - Signals can save and won't run functions
 * - `update` function on Signal that could be used to use the old value
 *   to set a new value
 * - The system is wrapped in a `createReactiveSystem` function so many
 *   systems can be run at the same time, for example for the
 *   developer tools context, so dev-tools context doesnt mess up the
 *   real context
 *
 * @url https://www.solidjs.com/
 * @url https://github.com/solidjs/solid
 * @url https://github.com/solidjs/signals
 */

export function createReactiveSystem() {
	const CLEAN = 0
	const STALE = 1
	const CHECK = 2

	/** @type {undefined | Computation} */
	let Owner

	/** @type {undefined | Computation} */
	let Listener

	/** @type {undefined | Memo[]} */
	let Updates

	/** @type {undefined | any[]} */
	let Effects

	let Time = 0

	const errorHandlerId = Symbol()

	function routeError(node, err) {
		const handler = node.context && node.context[errorHandlerId]
		if (handler) handler(err)
		else console.error(err)
	}

	function doRead(o) {
		if (Listener) {
			const sourceSlot = o.observers ? o.observers.length : 0

			if (Listener.sources) {
				Listener.sources.push(o)
				Listener.sourceSlots.push(sourceSlot)
			} else {
				Listener.sources = [o]
				Listener.sourceSlots = [sourceSlot]
			}

			const observerSlot = Listener.sources.length - 1

			if (sourceSlot) {
				o.observers.push(Listener)
				o.observerSlots.push(observerSlot)
			} else {
				o.observers = [Listener]
				o.observerSlots = [observerSlot]
			}
		}
	}

	let _writeTarget

	function _markObservers() {
		for (const observer of _writeTarget) {
			if (observer.state === 0 /* CLEAN */) {
				observer.queue()
				observer.observers && downstream(observer)
			}

			observer.state = 1 /* STALE */
		}
	}

	function doWrite(o) {
		if (o.observers && o.observers.length) {
			_writeTarget = o.observers
			runUpdates(_markObservers)
		}
	}

	// ROOT

	class Root {
		/** @type {undefined | Root} */
		owner

		/** @type {Computation | Computation[]} */
		owned

		/** @type {undefined | Function | Function[]} */
		cleanups

		/** @type {Record<symbol, unknown>} */
		context

		/**
		 * @param {Computation} owner
		 * @param {EffectOptions} [options]
		 */
		constructor(owner, options) {
			if (owner) {
				this.owner = owner

				if (owner.context) {
					this.context = owner.context
				}
			}

			options && assign(this, options)
		}
		/** @param {() => void} fn */
		addCleanups(fn) {
			if (!this.cleanups) {
				this.cleanups = fn
			} else if (isArray(this.cleanups)) {
				this.cleanups.push(fn)
			} else {
				this.cleanups = [this.cleanups, fn]
			}
		}
		/** @param {() => void} fn */
		cleanupCancel(fn) {
			if (!this.cleanups) {
			} else if (this.cleanups === fn) {
				this.cleanups = undefined
			} else if (isArray(this.cleanups)) {
				removeFromArray(this.cleanups, fn)
			}
		}
		/** @param {Computation} value */
		addOwned(value) {
			if (!this.owned) {
				this.owned = value
			} else if (isArray(this.owned)) {
				this.owned.push(value)
			} else {
				this.owned = [this.owned, value]
			}
		}

		dispose() {
			this.disposeOwned()
			this.doCleanups()
		}

		disposeOwned() {
			if (!this.owned) {
			} else if (isArray(this.owned)) {
				for (let i = this.owned.length - 1; i >= 0; i--) {
					this.owned[i].dispose()
				}
				this.owned = undefined
			} else {
				this.owned.dispose()
				this.owned = undefined
			}
		}

		doCleanups() {
			if (!this.cleanups) {
			} else if (isArray(this.cleanups)) {
				for (let i = this.cleanups.length - 1; i >= 0; i--) {
					try {
						this.cleanups[i]()
					} catch (err) {
						routeError(this, err)
					}
				}
				this.cleanups = undefined
			} else {
				try {
					this.cleanups()
				} catch (err) {
					routeError(this, err)
				}
				this.cleanups = undefined
			}
		}
	}

	// COMPUTATION

	class Computation extends Root {
		state = 1 /* STALE */

		updatedAt = 0

		/** @type {Function | undefined} */
		fn

		sources
		sourceSlots

		/**
		 * @param {Computation} owner
		 * @param {Function} fn
		 * @param {EffectOptions} [options]
		 */
		constructor(owner, fn, options) {
			super(owner, options)

			this.fn = fn

			owner && owner.addOwned(this)
		}

		update() {
			this.dispose()

			const time = Time

			try {
				runWith(this.fn, this, this)
			} catch (err) {
				this.state = 1 /* STALE */
				this.disposeOwned()
				this.updatedAt = time + 1
				routeError(this, err)
			}

			if (this.updatedAt < time) {
				this.updatedAt = time
			}
		}

		dispose() {
			if (this.sources && this.sources.length) {
				let source
				let observers
				let index

				let observer
				let slot
				while (this.sources.length) {
					source = this.sources.pop()
					observers = source.observers

					index = this.sourceSlots.pop()

					if (observers && observers.length) {
						observer = observers.pop()
						slot = source.observerSlots.pop()

						if (index < observers.length) {
							observer.sourceSlots[slot] = index
							observers[index] = observer
							source.observerSlots[index] = slot
						}
					}
				}
			}

			super.dispose()

			this.state = 0 /* CLEAN */
		}
		queue() {
			Effects.push(this)
		}
	}

	class Effect extends Computation {
		user = true

		/**
		 * @param {Computation} owner
		 * @param {Function} fn
		 * @param {EffectOptions} [options]
		 */
		constructor(owner, fn, options) {
			super(owner, fn, options)

			Effects ? Effects.push(this) : batch(() => this.update())
		}
	}

	class SyncEffect extends Computation {
		/**
		 * @param {Computation} owner
		 * @param {Function} fn
		 * @param {EffectOptions} [options]
		 */
		constructor(owner, fn, options) {
			super(owner, fn, options)

			batch(() => this.update())
		}
	}

	// SIGNALS

	/** @template in T */
	class Memo extends Computation {
		value

		observers
		observerSlots

		/**
		 * @param {Computation} owner
		 * @param {Function} fn
		 * @param {SignalOptions<T>} [options] - Accepts `equals`
		 */
		constructor(owner, fn, options) {
			// Memo extends Computation (EffectOptions) but accepts
			// SignalOptions<T>. Pass undefined to super — Memo
			// applies the signal-specific options itself below.
			super(owner, fn, undefined)

			if (options) {
				assign(this, options)
				if (options.equals === false) {
					this.equals = this.equalsFalse
				}
			}
		}

		read = () => {
			if (this.state === 1 /* STALE */) {
				this.update()
			} else if (this.state === 2 /* CHECK */) {
				const updates = Updates
				Updates = undefined
				runUpdates(() => upstream(this))
				Updates = updates
			}

			doRead(this)

			return this.value
		}

		write(value) {
			if (!this.equals(this.value, value)) {
				this.value = value

				doWrite(this)
			}
		}
		/**
		 * @param {T} a
		 * @param {T} b
		 */
		equals(a, b) {
			return a === b
		}
		/**
		 * @param {T} a
		 * @param {T} b
		 */
		equalsFalse(a, b) {
			return false
		}
		update() {
			this.dispose()

			const time = Time

			try {
				const nextValue = runWith(this.fn, this, this)

				if (this.updatedAt <= time) {
					this.write(nextValue)
					this.updatedAt = time
				}
			} catch (err) {
				this.state = 1 /* STALE */
				this.disposeOwned()
				this.updatedAt = time + 1
				routeError(this, err)
			}
		}
		queue() {
			Updates.push(this)
		}
	}

	/** @template in T */
	class Derived extends Memo {
		value = nothing

		isResolved

		/**
		 * @param {Computation} owner
		 * @param {unknown[]} fn
		 */
		constructor(owner, fn) {
			// @ts-expect-error
			super(owner, fn)

			return this.self()
		}

		self() {
			return assign(
				/** @type {SignalFunction<Accessed<T>>} */ (
					/** @type {unknown} */ (...args) => {
						return args.length ? this.write(args[0]) : this.read()
					}
				),
				this,
			)
		}

		resolved = () => {
			this.read() // tracking
			return this.isResolved === null
		}
		run = () => {
			this.update()
		}
		_runFn = () => {
			// @ts-expect-error
			this.write(this.fn[0](), this.fn.slice(1))
		}
		update() {
			this.dispose()

			const time = Time

			try {
				this.lastWrite = {}

				runWith(this._runFn, this, this)
			} catch (err) {
				this.state = 1 /* STALE */
				this.disposeOwned()
				this.updatedAt = time + 1
				routeError(this, err)
			}
		}
		write(nextValue, fns) {
			this.isResolved = undefined

			const mine =
				fns === undefined ? (this.lastWrite = {}) : this.lastWrite

			withValue(
				nextValue,
				nextValue => {
					if (Listener || this.lastWrite === mine) {
						if (fns && fns.length) {
							this.write(() => fns[0](nextValue), fns.slice(1))
						} else {
							this.isResolved = null

							this.writeNextValue(nextValue)
							this.updatedAt = Time
							// Mark CLEAN so a subsequent read does
							// not re-run the original fn and clobber
							// the user-written value. The update()
							// path already set CLEAN via dispose(),
							// so this is a no-op there.
							this.state = 0 /* CLEAN */

							this.resolve && this.resolve(this)
						}
					}
				},
				() => {
					// is a promise so restore `then`
					this.thenRestore()

					// remove the old value while the promise is resolving
					// to avoid the "Florida - New York City" problem
					this.writeNextValue(nothing)
				},
			)
		}
		writeNextValue(value) {
			if (!this.equals(this.value, value)) {
				this.value = value

				doWrite(this)
			}
		}

		/**
		 * Thenable stuff. It has to be a property so assign works
		 * properly
		 */
		then = (resolve, reject) => {
			this._then(resolve, reject)
		}
		_then(resolve, reject) {
			this.resolve = () => {
				this.then = undefined
				this.resolve = undefined
				resolve(this.self())
			}
			if (this.resolved()) {
				this.resolve()
			}
		}
		thenRestore() {
			if (!this.then) {
				// TODO: unsure if has to be restored
				this.then = this._then
			}
		}
	}

	// API

	/**
	 * Creates a new root
	 *
	 * @template T
	 * @param {(dispose: () => void) => T} fn
	 * @param {EffectOptions} [options]
	 * @returns {T}
	 */
	function root(fn, options) {
		const root = new Root(Owner, options)
		return runWithOwner(root, () => fn(() => root.dispose()))
	}

	// SIGNAL

	/**
	 * @param {any} a
	 * @param {any} b
	 */
	function equalsFalse(a, b) {
		return false
	}

	/**
	 * @param {any} a
	 * @param {any} b
	 */
	function equals(a, b) {
		return a === b
	}

	/**
	 * Creates a signal
	 *
	 * @template T
	 * @param {T} [value] - Initial value of the signal
	 * @param {SignalOptions<T>} [options] - Signal options
	 * @returns {SignalObject<T>}
	 */
	/* #__NO_SIDE_EFFECTS__ */ function signal(value, options) {
		const o = {
			observers: undefined,
			observerSlots: undefined,
		}

		let _equals = equals

		function read() {
			if (Listener) {
				doRead(o)
			}

			return value
		}
		function write(val) {
			if (!_equals(value, val)) {
				value = val

				doWrite(o)

				return true
			}
			return false
		}
		function update(val) {
			return write(untrack(() => val(value)))
		}

		const s = /** @type {any} */ ([read, write, update])

		s.read = read
		s.write = write
		s.update = update

		if (options) {
			assign(s, options)
			if (s.equals === false) _equals = equalsFalse
			else if (s.equals) _equals = s.equals
		}

		return s
	}

	/**
	 * Creates an effect
	 *
	 * @template T
	 * @param {() => T} fn
	 * @param {EffectOptions} [options]
	 * @returns {void}
	 */
	function effect(fn, options) {
		new Effect(Owner, fn, options)
	}

	/**
	 * Creates an run once effect
	 *
	 * @template T
	 * @param {() => T} fn
	 * @param {EffectOptions} [options]
	 */
	function track(fn, options) {
		let ran
		new Effect(
			Owner,
			() => {
				if (ran === undefined) {
					ran = null
					fn()
				}
			},
			options,
		)
	}

	/**
	 * Creates a syncEffect
	 *
	 * @template T
	 * @param {() => T} fn
	 * @param {EffectOptions} [options]
	 * @returns {void}
	 */
	function syncEffect(fn, options) {
		new SyncEffect(Owner, fn, options)
	}

	/**
	 * Creates an effect with explicit dependencies
	 *
	 * @template T
	 * @param {() => any} depend - Function that causes tracking
	 * @param {() => T} fn - Function that wont cause tracking
	 * @param {EffectOptions} [options]
	 * @returns {void}
	 */
	function on(depend, fn, options) {
		effect(() => {
			depend()
			untrack(fn)
		}, options)
	}

	/**
	 * Creates a read-only signal from the return value of a function
	 * that automatically updates
	 *
	 * The return type intersects `SignalAccessor<T>` with a phantom `{
	 * readonly memo?: void }` property. The phantom never exists at
	 * runtime — its sole purpose is to give TypeScript more structural
	 * information so it can infer `T` cleanly when memo() is called
	 * inline inside another generic context, e.g. `<For each={memo(()
	 * => [...])}>`. Without it, bidirectional inference between two
	 * generic calls collapses `T` to `unknown`.
	 *
	 * @template T
	 * @param {() => T} fn - Function to re-run when dependencies change
	 * @param {SignalOptions<T>} [options]
	 * @returns {SignalAccessor<T> & { readonly memo?: void }}
	 */
	/* #__NO_SIDE_EFFECTS__ */ function memo(fn, options = undefined) {
		return /** @type {SignalAccessor<T> & { readonly memo?: void }} */ (
			/** @type {unknown} */ (new Memo(Owner, fn, options).read)
		)
	}

	/**
	 * Lazy and writable version of `memo` that unwraps and tracks
	 * functions and promises recursively
	 */
	/* #__NO_SIDE_EFFECTS__ */ const derived =
		/** @type {import('#type/derived.d.ts').derived} */ (
			/** @type {unknown} */ (...fn) =>
				/** @type {import('#type/derived.d.ts').derived} */ (
					/** @type {unknown} */ (new Derived(Owner, fn))
				)
		)

	/**
	 * Batches changes to signals
	 *
	 * @template T
	 * @param {() => T} fn
	 */
	const batch = runUpdates

	/**
	 * Returns current owner
	 *
	 * @returns {Computation}
	 */
	function owner() {
		return Owner
	}

	/**
	 * Runs a function with owner and listener
	 *
	 * @param {Function} fn
	 * @param {Computation} owner
	 * @param {Listener} [listener]
	 */
	function runWith(fn, owner, listener = undefined) {
		if (listener === Listener && owner === Owner) {
			return fn()
		}

		const prevOwner = Owner
		const prevListener = Listener

		Owner = owner
		Listener = listener

		try {
			return fn()
		} finally {
			Owner = prevOwner
			Listener = prevListener
		}
	}
	function runWithOwner(owner, fn) {
		try {
			return runWith(() => runUpdates(fn, true), owner)
		} catch (err) {
			routeError(owner, err)
		}
	}

	/**
	 * Disables tracking for a function
	 *
	 * @template T
	 * @param {() => T} fn - Function to run with tracking disabled
	 * @returns {T}
	 */
	function untrack(fn) {
		if (Listener === undefined) {
			return fn()
		}

		return runWith(fn, Owner)
	}

	/**
	 * Runs a callback on cleanup, returns callback
	 *
	 * @template {() => void} T
	 * @param {T} fn
	 * @returns {T}
	 */
	function cleanup(fn) {
		Owner?.addCleanups(fn)
		return fn
	}

	/**
	 * Runs `fn` and routes any error — synchronous or reactive — from
	 * its descendants to `handler` instead of the console.
	 *
	 * @template T
	 * @param {() => T} fn
	 * @param {(err: unknown) => void} handler
	 * @returns {T | undefined}
	 */
	function catchError(fn, handler) {
		let result
		syncEffect(() => {
			const parentHandler =
				/** @type {((err: unknown) => void) | undefined} */ (
					Owner.context && Owner.context[errorHandlerId]
				)

			const safeHandler = err => {
				try {
					handler(err)
				} catch (handlerErr) {
					if (parentHandler) parentHandler(handlerErr)
					else console.error(handlerErr)
				}
			}

			Owner.context = {
				...Owner.context,
				[errorHandlerId]: safeHandler,
			}
			try {
				result = untrack(fn)
			} catch (err) {
				Owner.disposeOwned()
				safeHandler(err)
			}
		})
		return result
	}

	// UPDATES

	function runTop(node) {
		switch (node.state) {
			case 0 /* CLEAN */: {
				break
			}
			case 2 /* CHECK */: {
				upstream(node)
				break
			}

			default: {
				const ancestors = []

				do {
					node.state && ancestors.push(node)

					node = node.owner
				} while (node && node.updatedAt < Time)

				for (let i = ancestors.length - 1, updates; i >= 0; i--) {
					node = ancestors[i]

					switch (node.state) {
						case 1 /* STALE */: {
							node.update()
							break
						}
						case 2 /* CHECK */: {
							updates = Updates
							Updates = undefined
							runUpdates(() => upstream(node, ancestors[0]))
							Updates = updates
							break
						}
					}
				}
			}
		}
	}

	/**
	 * @template T
	 * @param {() => T} fn
	 * @param {boolean} init
	 * @returns {T}
	 */
	function runUpdates(fn, init = false) {
		if (Updates) {
			return fn()
		}

		let wait = false

		if (!init) {
			Updates = []
		}

		if (Effects) {
			wait = true
		} else {
			Effects = []
		}

		Time++

		try {
			const res = fn()

			if (Updates) {
				for (const update of Updates) {
					runTop(update)
				}
			}
			Updates = undefined

			if (!wait) {
				const effects = Effects
				Effects = undefined
				effects.length && runUpdates(() => runEffects(effects))
			}

			return res
		} catch (err) {
			if (!wait) {
				Effects = undefined
			}
			Updates = undefined

			throw err
		}
	}

	function runEffects(queue) {
		let userLength = 0
		for (const effect of queue) {
			if (effect.user) {
				queue[userLength++] = effect
			} else {
				runTop(effect)
			}
		}

		for (let i = 0; i < userLength; i++) {
			runTop(queue[i])
		}
	}

	function upstream(node, ignore) {
		node.state = 0 /* CLEAN */

		for (const source of node.sources) {
			if (source.sources) {
				switch (source.state) {
					case 1 /* STALE */: {
						if (source !== ignore && source.updatedAt < Time) {
							runTop(source)
						}
						break
					}
					case 2 /* CHECK */: {
						upstream(source, ignore)
						break
					}
				}
			}
		}
	}

	function downstream(node) {
		for (const observer of node.observers) {
			if (observer.state === 0 /* CLEAN */) {
				observer.state = 2 /* CHECK */
				observer.queue()
				observer.observers && downstream(observer)
			}
		}
	}

	/**
	 * Creates a context and returns a function to get or set the value
	 *
	 * @template T
	 * @param {T} [defaultValue] - Default value for the context
	 * @returns {Context<T>}
	 */
	/* #__NO_SIDE_EFFECTS__ */ function context(
		defaultValue = undefined,
	) {
		const id = Symbol()

		/**
		 * @overload Runs `fn` with the full context value
		 * @param {T} newValue - New value for the context
		 * @param {() => JSX.Element} fn - Callback to run with the new
		 *   context value
		 * @returns {JSX.Element} Context value
		 */
		/**
		 * @overload Runs `fn` with a partial override of the context
		 * @param {Partial<T>} newValue - Partial override
		 * @param {() => JSX.Element} fn - Callback to run with the new
		 *   context value
		 * @returns {JSX.Element} Context value
		 */
		/**
		 * @overload Gets the context value
		 * @returns {T} Context value
		 */
		function useContext(newValue, fn) {
			if (newValue === undefined) {
				return Owner?.context && Owner.context[id] !== undefined
					? Owner.context[id]
					: defaultValue
			} else {
				let ret
				syncEffect(() => {
					Owner.context = {
						...Owner.context,
						[id]: newValue,
					}
					ret = untrack(fn)
				})
				return ret
			}
		}

		/**
		 * Sets the `value` for the context
		 *
		 * @param {object} props
		 * @param {Partial<T> | { [K in keyof T]?: Accessor<T[K]> }} props.value
		 * @param {JSX.Element} [props.children]
		 * @returns {JSX.Element}
		 * @url https://pota.quack.uy/Reactivity/Context
		 */
		useContext.Provider = props =>
			useContext(/** @type {Partial<T>} */ (props.value), () =>
				// @ts-expect-error `toHTML` is attached by renderer.js at module init
				context.toHTML(props.children),
			)

		/**
		 * Maps context following `parent` property (if any). When `true`
		 * is returned from the callback it stops walking.
		 *
		 * @param {(context: T) => boolean | void} callback
		 * @param {T} [context]
		 * @returns {boolean}
		 */
		useContext.walk = (callback, context) =>
			walkParents(context || useContext(), 'parent', callback)

		return useContext
	}

	/**
	 * Returns an owned function, that will only run if the owner wasnt
	 * dispose already. `onCancel` will run if the owner of the owned
	 * function is disposed, and wont run if the owned function runs.
	 *
	 * @template T
	 * @template A
	 * @param {((...args: A[]) => T) | Function} cb
	 * @param {() => void} [onCancel]
	 */
	const owned = (cb, onCancel) => {
		if (cb) {
			const o = Owner

			/**
			 * Canceling prevent the callback from running and runs
			 * `onCancel` if provided.
			 */
			let cleaned

			cleanup(() => {
				// only run onCancel when actually is canceled
				onCancel && cleaned === undefined && onCancel()
				cleaned = null
			})

			return (...args) => {
				// if the function runs, then it wont be canceled
				onCancel = null

				// only run callback when owner wasnt disposed
				return cleaned !== null && runWithOwner(o, () => cb(...args))
			}
		}
		return noop
	}

	/**
	 * Unwraps and tracks functions and promises recursively providing
	 * the result to a callback
	 *
	 * @template T
	 * @param {Attribute<T>} value
	 * @param {(value: T) => void} fn
	 */
	function withValue(
		value,
		fn,
		writeDefaultValue = noop,
		wroteValue = { value: false },
		resolved = [],
	) {
		if (isFunction(value)) {
			// TODO maybe change this to be a memo

			effect(() =>
				withValue(
					value(),
					fn,
					writeDefaultValue,
					wroteValue,
					resolved,
				),
			)
		} else if (isArray(value) && !resolved.includes(value)) {
			// TODO maybe do same for objects ...

			resolved.push(value)

			// when empty it should update too
			if (value.length === 0) {
				fn(value)
				return
			}

			let pending = value.length
			value.forEach((item, i) => {
				withValue(
					item,
					item => {
						value[i] = item
						if (--pending === 0) {
							withValue(
								value,
								fn,
								writeDefaultValue,
								wroteValue,
								resolved,
							)
						}
					},
					writeDefaultValue,
					wroteValue,
					resolved,
				)
			})
		} else if (isPromise(value)) {
			const remove = asyncTracking.add()
			/**
			 * WriteDefaultValue is used to avoid a double write. If the
			 * value has no promises, then it will be a native value or a
			 * function, which will resolve without having to wait.
			 *
			 * In case of promises, the value is resolved at a later point
			 * in time, so we need an intermediate default
			 */
			!wroteValue.value && writeDefaultValue()
			wroteValue.value = true

			value.then(
				owned(value => {
					remove()
					withValue(
						value,
						fn,
						writeDefaultValue,
						wroteValue,
						resolved,
					)
				}, remove),
				owned(err => {
					remove()
					throw err
				}, remove),
			)
		} else {
			fn(value)
		}
	}

	/**
	 * Unwraps functions and promises recursively canceling if owner
	 * gets disposed
	 */
	const resolve = (value, cbs) =>
		isFunction(value)
			? track(() => resolve(getValue(value), cbs))
			: isPromise(value)
				? value.then(
						owned(value => resolve(value, cbs)),
						owned(err => {
							throw err
						}),
					)
				: cbs.length
					? resolve(() => cbs[0](value), cbs.slice(1))
					: value

	/**
	 * Unwraps functions and promises recursively canceling if owner
	 * gets disposed
	 *
	 * @type {import('#type/action.d.ts').action}
	 */
	const action = (...cbs) =>
		owned((...args) => {
			resolve(() => cbs[0](...args), cbs.slice(1))
		})

	/** Utilities exposed for tracking async work from user-land. */

	const asyncTracking = (() => {
		let added = false
		let fns = []
		let count = 0

		function add() {
			count++
			let removed
			return () => {
				if (removed === undefined) {
					removed = null
					--count === 0 && queue()
				}
			}
		}

		function ready(fn) {
			fns.push(owned(fn))
			queue()
		}

		function queue() {
			if (!added && fns.length) {
				added = true
				queueMicrotask(() => queueMicrotask(() => run()))
			}
		}
		function run() {
			added = false

			if (count === 0) {
				const cbs = fns.slice()
				fns.length = 0
				call(cbs)
			}
		}
		return { add, ready }
	})()

	/** Suspense */
	class createSuspenseContext {
		s = signal(false)
		c = 0
		add() {
			this.c++
			const asyncRemove = asyncTracking.add()
			let removed
			return () => {
				if (removed === undefined) {
					removed = null
					if (--this.c === 0) {
						this.s.write(true)
					}
					asyncRemove()
				}
			}
		}
		isEmpty() {
			return this.c === 0
		}
	}

	const useSuspense = context(new createSuspenseContext())

	// export

	/** Returns the current reactive listener, if any. */
	function listener() {
		return Listener
	}

	return {
		action,
		asyncTracking,
		batch,
		catchError,
		cleanup,
		context,
		createSuspenseContext,
		derived,
		effect,
		listener,
		memo,
		on,
		owned,
		owner,
		root,
		runWithOwner,
		signal,
		syncEffect,
		untrack,
		useSuspense,
		withValue,
	}
}
